// 1. Limpeza do JSON
const rawOutput = $('AI Agent - Character Definitions').first().json.output;

// CORREÇÃO: Pegar o índice [0] do match para obter a string
const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
const cleanJson = jsonMatch ? jsonMatch[0] : rawOutput;

const historiaHash = Math.random().toString(36).substring(2, 10).toUpperCase();

try {
  const parsed = JSON.parse(cleanJson);

  // 2. NORMALIZAÇÃO: O seu JSON atual tem os capítulos dentro de parsed.story como um OBJETO
  let chaptersRaw = parsed.chapters || parsed.story || [];

  // Se 'chaptersRaw' for um objeto (como no seu erro), transforma em Array
  let chaptersArray = [];
  if (!Array.isArray(chaptersRaw) && typeof chaptersRaw === 'object') {
    chaptersArray = Object.values(chaptersRaw);
  } else {
    chaptersArray = chaptersRaw;
  }

  if (chaptersArray.length === 0) throw new Error("Nenhum capítulo encontrado");

  return chaptersArray.map((item, index) => {
    const titulo = item.title || "Capítulo " + (index + 1);
    const conteudoStory = item.story || ""; 
    let promptImg = item.imageGeneration || "";

    let textoParaAudio = `${titulo}, <break time="500ms"/> ${conteudoStory}`;

    let textoSSML = textoParaAudio
      .replace(/(\.|\?|!)\s+/g, '$1 <break time="300ms"/> ') 
      .replace(/\n\n/g, ' <break time="1s"/> ');

    const narrativaSSML = `<speak><prosody rate="92%">${textoSSML}</prosody></speak>`;

    return {
      json: {
        historia_id: historiaHash,
        capitulo_numero: index + 1,
        titulo: titulo,
        texto_original: conteudoStory,
        texto_ssml: narrativaSSML,
        prompt_img: promptImg
      }
    };
  });

} catch (e) {
  return [{ json: { erro: "Falha no Parse", detalhes: e.message, primeiro_caractere: cleanJson[0] } }];
}
